function Tably(selector,options={}){this.container=document.querySelector(selector);if(!this.container){console.error(`Tably: ${selector} does not exist`);return}this.tabs=Array.from(this.container.querySelectorAll("li a"));if(!this.tabs.length){console.error(`Tably: No tabs found in ${selector}`);return}this.panels=this.tabs.map(tab=>document.querySelector(tab.getAttribute("href")));if(this.panels.includes(null)){console.error(`Tably: Panel not found`);return}this.opt=Object.assign({remember:false,onChange:null,classActive:"tably--active"},options);this._clearRelax=/[^a-zA-Z0-9]/g;this._paramKey=selector.replace(this._clearRelax,"");this._init()}Tably.prototype._init=function(){const params=new URLSearchParams(window.location.search);const tabSearch=params.get(this._paramKey);const activeToTab=this.opt.remember&&tabSearch||this.tabs[0].getAttribute("href").replace(this._clearRelax,"");const tab=this.tabs.find(tab=>tab.getAttribute("href").replace(this._clearRelax,"")===activeToTab);this.currentTab=tab;this._activateTab(tab||this.tabs[0],false,false);this._boundActivateTab=this._handleTabClick.bind(this);this.tabs.forEach(tab=>{tab.addEventListener("click",this._boundActivateTab)})};Tably.prototype._handleTabClick=function(e){e.preventDefault();this._tryActivateTab(e.currentTarget)};Tably.prototype._activateTab=function(tab,isClick=true,updateUrl=true){this.tabs.forEach(t=>t.closest("li").classList.remove(this.opt.classActive));tab.closest("li").classList.add(this.opt.classActive);this.panels.forEach(panel=>panel.hidden=true);const targetPanel=document.querySelector(tab.getAttribute("href"));if(targetPanel)targetPanel.hidden=false;if(updateUrl){const params=new URLSearchParams(window.location.search);params.set(this._paramKey,tab.getAttribute("href").replace(this._clearRelax,""));history.replaceState(null,null,`?${params}`)}if(this.opt.onChange&&isClick){this.opt.onChange({tab:tab,panel:targetPanel})}};Tably.prototype.switch=function(input){if(!this.tabs)return;let targetTab;if(typeof input==="string"){targetTab=this.tabs.find(tab=>tab.getAttribute("href")===input)}else if(this.tabs.includes(input)){targetTab=input}if(!targetTab){console.error(`Tably: No tab found for ${input}`);return}this._tryActivateTab(targetTab)};Tably.prototype._tryActivateTab=function(targetTab){if(targetTab!==this.currentTab){this.currentTab=targetTab;this._activateTab(targetTab)}};Tably.prototype.destroy=function(){if(!this.tabs)return;this.tabs.forEach(tab=>{tab.removeEventListener("click",this._boundActivateTab)});this.tabs.forEach(t=>t.closest("li").classList.remove(this.opt.classActive));this.panels.forEach(panel=>panel.hidden=false);this.container=null;this.tabs=null;this.panels=null;this._boundActivateTab=null;this.currentTab=null};